// ValidateBriefInputRequestBody runs the validations defined on
// brief-inputRequestBody
func ValidateBriefInputRequestBody(body *BriefInputRequestBody) (err error) {
	if body.ProgramType == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("program_type", "body"))
	}
	if body.EventSlug == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("event_slug", "body"))
	}
	if body.ProgramType != nil {
		if !(*body.ProgramType == "events" || *body.ProgramType == "education" || *body.ProgramType == "membership") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.program_type", *body.ProgramType, []any{"events", "education", "membership"}))
		}
	}
	return
}

// ValidateCampaignCreateInputRequestBody runs the validations defined on
// campaign-create-inputRequestBody
func ValidateCampaignCreateInputRequestBody(body *CampaignCreateInputRequestBody) (err error) {
	if body.Platforms == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("platforms", "body"))
	}
	if len(body.Platforms) < 1 {
		err = goa.MergeErrors(err, goa.InvalidLengthError("body.platforms", body.Platforms, len(body.Platforms), 1, true))
	}
	for _, e := range body.Platforms {
		if !(e == "google-ads" || e == "linkedin-ads" || e == "meta-ads" || e == "reddit-ads" || e == "twitter-ads" || e == "microsoft-ads" || e == "hubspot") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.platforms[*]", e, []any{"google-ads", "linkedin-ads", "meta-ads", "reddit-ads", "twitter-ads", "microsoft-ads", "hubspot"}))
		}
	}
	return
}

// ValidateCampaignUpdateInputRequestBody runs the validations defined on
// campaign-update-inputRequestBody
func ValidateCampaignUpdateInputRequestBody(body *CampaignUpdateInputRequestBody) (err error) {
	if body.CampaignName == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("campaign_name", "body"))
	}
	if body.Status == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("status", "body"))
	}
	return
}
